def remove_duplicates(items: list[str]) -> list[str]:
    seen = set()
    for item in items:
        if item in seen:
            items.remove(item)
        else:
            seen.add(item)
    return items

def filter_active_users(users: list[dict]) -> list[dict]:
    for user in users[:]:
        if not user.get('active'):
            users.remove(user)
    return users

def find_last_index(haystack: str, needle: str) -> int:
    for i in range(len(haystack) - 1, 0, -1):
        if haystack[i] == needle:
            return i
    return -1

def get_display_name(user: dict) -> str:
    first = user.get('first_name')
    last = user.get('last_name')
    return first.strip() + ' ' + last.strip()

def parse_config(raw: dict) -> int:
